// Parse Claude API response and flatten prospects into rows
const response = $input.first().json;
let content = '';

// Extract text from Claude response
if (response.content && Array.isArray(response.content)) {
  content = response.content.map(c => c.text || '').join('');
} else if (typeof response === 'string') {
  content = response;
}

// Parse JSON from response (handle markdown code blocks)
let prospects = [];
try {
  // Remove markdown code fences if present
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  prospects = JSON.parse(cleaned);
} catch (e) {
  // Try to find JSON array in the text
  const match = content.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (match) {
    prospects = JSON.parse(match[0]);
  } else {
    throw new Error('Could not parse prospects JSON from Claude response: ' + e.message);
  }
}

if (!Array.isArray(prospects)) {
  prospects = [prospects];
}

// Return each prospect as a separate item
return prospects.map((prospect, index) => ({
  json: {
    index: index + 1,
    company_name: prospect.company_name || '',
    website: prospect.website || '',
    employee_count: prospect.employee_count || 0,
    industry_vertical: prospect.industry_vertical || '',
    decision_maker_name: prospect.decision_maker_name || '',
    decision_maker_title: prospect.decision_maker_title || '',
    decision_maker_email_guess: prospect.decision_maker_email_guess || '',
    pain_signals: prospect.pain_signals || [],
    growth_signals: prospect.growth_signals || [],
    os_readiness_score: prospect.os_readiness_score || 0,
    priority_tier: prospect.priority_tier || 'COLD',
    engagement_hook: prospect.engagement_hook || '',
    recommended_programme: prospect.recommended_programme || 'Leader as Coach',
    source: 'claude_connector',
    found_at: new Date().toISOString()
  }
}));

